import React, { useState, useRef } from "react";
import GoogleMapView from "../components/GoogleMapView";
import CameraCapture from "../components/CameraCapture";

function Journey() {

  const [vehicleImage, setVehicleImage] = useState(null);
  const handleCapture = (image) => {

    setVehicleImage(image);

  };
  const [origin, setOrigin] = useState("");
  const [destination, setDestination] = useState("");
  const [journeyStarted, setJourneyStarted] = useState(false);

  const lastLat = useRef(null);
  const lastLon = useRef(null);
  const stopTimer = useRef(null);

  // 🔴 SEND LOCATION TO BACKEND
  const sendAlertToParent = async (lat, lon) => {

    await fetch("http://localhost:5000/alert", {

      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },

      body: JSON.stringify({
        lat: lat,
        lon: lon
      })

    });

  };

  // 🔵 FIND NEAREST POLICE STATION
  const findPoliceStation = async (lat, lon) => {

    const query = `
    [out:json];
    node["amenity"="police"](around:2000,${lat},${lon});
    out;
    `;

    const url =
      "https://overpass-api.de/api/interpreter?data=" +
      encodeURIComponent(query);

    const res = await fetch(url);
    const data = await res.json();

    if (data.elements.length > 0) {

      const police = data.elements[0];

      const policeLat = police.lat;
      const policeLon = police.lon;

      alert("🚓 Nearest police station found! Opening route.");

      window.open(
        `https://www.google.com/maps/dir/${lat},${lon}/${policeLat},${policeLon}`,
        "_blank"
      );

    } else {

      alert("No police station found nearby");

    }

  };

  // 📍 SHARE CURRENT LOCATION
  const shareLocation = () => {

    navigator.geolocation.getCurrentPosition((position) => {

      const lat = position.coords.latitude;
      const lon = position.coords.longitude;

      const locationLink =
        `https://maps.google.com/?q=${lat},${lon}`;

      const whatsappURL =
        `https://wa.me/?text=My%20Live%20Location:%20${locationLink}`;

      window.open(whatsappURL, "_blank");

    },
      () => {
        alert("Unable to get location");
      });

  };

  const startTracking = () => {

    navigator.geolocation.watchPosition(

      async (position) => {

        const lat = position.coords.latitude;
        const lon = position.coords.longitude;

        const res = await fetch(
          `https://nominatim.openstreetmap.org/reverse?format=json&lat=${lat}&lon=${lon}`
        );

        const data = await res.json();

        setOrigin(data.display_name);

        if (lastLat.current !== null) {

          const distance =
            Math.sqrt(
              Math.pow(lat - lastLat.current, 2) +
              Math.pow(lon - lastLon.current, 2)
            );

          if (distance < 0.0001) {

            if (!stopTimer.current) {

              stopTimer.current = setTimeout(() => {

                alert("🚨 Alert: User stopped moving!");

                sendAlertToParent(lat, lon);

                findPoliceStation(lat, lon);

              }, 180000);

            }

          } else {

            clearTimeout(stopTimer.current);
            stopTimer.current = null;

          }

        }

        lastLat.current = lat;
        lastLon.current = lon;

      },

      (error) => {
        alert("Location tracking failed");
      },

      {
        enableHighAccuracy: true
      }

    );

  };

  // 🚀 START JOURNEY
  const startJourney = () => {

    if (!destination) {

      alert("Please enter destination first");
      return;

    }

    setJourneyStarted(true);

    startTracking();

  };
  const startVoiceDetection = () => {

    const recognition = new window.webkitSpeechRecognition();

    recognition.continuous = true;
    recognition.lang = "en-IN";

    recognition.onresult = (event) => {

      const speech =
        event.results[event.results.length - 1][0].transcript
          .toLowerCase();

      console.log("Voice detected:", speech);

      if (speech.includes("bhaiya kaha ja rahe ho")) {

        alert("🚨 Secret code detected!");

        triggerEmergency();

      }

    };

    recognition.start();

  };
  return (

    <div className="container">

      <div className="card">

        <h2>Journey Details</h2>

        <input
          type="text"
          placeholder="Current Location"
          value={origin}
          readOnly
        />

        <input
          type="text"
          placeholder="Final Destination"
          value={destination}
          onChange={(e) => setDestination(e.target.value)}
          disabled={journeyStarted}
        />

        <button onClick={startJourney}>
          Start Journey
        </button>

        <button className="share" onClick={shareLocation}>
          Share My Location
        </button>

        <CameraCapture onCapture={handleCapture} />

        {vehicleImage && (

          <div>

            <h4>Captured Vehicle</h4>

            <img
              src={vehicleImage}
              alt="vehicle"
              style={{ width: "300px" }}
            />

          </div>

        )}

      </div>

      <GoogleMapView
        origin={origin}
        destination={destination}
      />

    </div>

  );

}

export default Journey;
